import React, { Component } from 'react';
import Container from '../../components/Container';
import './style.css';

class Counter extends Component {
    componentWillUnmount() {
        console.log('Counter componentWillUnmount');
    }

    render() {
        const { count, onIncrease, onDecrease } = this.props;

        return (
            <div className="counter-card">
                <div className="counter-badge">Interactive Counter</div>
                <p className="counter-label">Current Count</p>
                <p className="counter-value">{count}</p>
                <div className="counter-actions">
                    <button className="counter-button secondary" onClick={onDecrease}>Decrease</button>
                    <button className="counter-button primary" onClick={onIncrease}>Increase</button>
                </div>
            </div>
        );
    }
}

export default class LifeCyclePage extends Component {
    constructor(props) {
        super(props);
        console.log('constructor');
    }

    state = {
        count: 0,
        isCounterExist: true,
    }

    static getDerivedStateFromProps(props , state) {
        console.log('getDerivedStateFromProps', props, state);
        return null;
    }

    componentDidMount() {
        console.log('componentDidMount');
    }

    componentDidUpdate() {
        console.log('componentDidUpdate');
        if (this.state.count === 15 && this.state.isCounterExist) {
            console.log('Count reached 15');
            this.setState({ isCounterExist: false });
        }
    }

    handelIncrease = () => {
        this.setState(prevState => ({
            count: prevState.count + 1
        }));
    }

    handelDecrease = () => {
        this.setState(prevState => ({
            count: prevState.count > 0 ? prevState.count - 1 : 0
        }));
    }

    handleReset = () => {
        this.setState({
            count: 0,
            isCounterExist: true,
        });
    }

    render() {
        console.log("render");
        return (
            <Container>
                <section className="lifecycle-page">
                    <div className="lifecycle-hero">
                        <p className="lifecycle-kicker">React Class Lifecycle</p>
                        <h1>LifeCyclePage</h1>
                        <p className="lifecycle-description">
                            The counter disappears automatically when the value reaches 15 so you can watch the lifecycle logs in the console.
                        </p>
                    </div>

                    <div className="lifecycle-panel">
                {this.state.isCounterExist && (
                    <Counter
                        {...{
                            count: this.state.count,
                            onIncrease: this.handelIncrease,
                            onDecrease: this.handelDecrease
                        }}
                    />
                )}
                        {!this.state.isCounterExist && (
                            <div className="counter-card counter-finished">
                                <p className="counter-badge">Unmounted</p>
                                <h2>Counter hidden at 15</h2>
                                <p className="lifecycle-description">
                                    Open the browser console to see <code>componentWillUnmount</code>.
                                </p>
                                <button className="counter-button primary" onClick={this.handleReset}>Reset Counter</button>
                            </div>
                        )}
                    </div>
                </section>
            </Container>
        );
    }
}
